from decimal import Decimal

class Account:
    def __init__(self, account_number, balance):
        self.account_number = account_number
        self.balance = Decimal(balance)

def process_transaction(account, transaction_amount):
    """
    Updates the account balance based on the transaction amount.

    Args:
        account: The account object.
        transaction_amount: The amount of the transaction.

    Returns:
        The updated account object.
    """

    account.balance += Decimal(transaction_amount)
    return account

def update_balances(accounts, transactions):
    """
    Updates the balances of all accounts based on the list of transactions.

    Args:
        accounts: A list of account objects.
        transactions: A list of tuples containing account number and transaction amount.

    Returns:
        A list of updated account objects.
    """

    for account_number, transaction_amount in transactions:
        for account in accounts:
            if account.account_number == account_number:
                account = process_transaction(account, transaction_amount)

    return accounts